    // Read /proc/stat twice with a short gap to compute real CPU usage
    const readStat = () => {
      const stat = fs.readFileSync('/proc/stat', 'utf8');
      const line = stat.split('\n')[0]; // cpu aggregate line
      const parts = line.trim().split(/\s+/).slice(1).map(Number);
      // fields: user, nice, system, idle, iowait, irq, softirq, steal, guest, guest_nice
      const idle = parts[3] + (parts[4] || 0); // idle + iowait
      const total = parts.reduce((a, b) => a + b, 0);
      return { idle, total };
    };

    const s1 = readStat();
    // Small busy-wait style sleep using execSync
    execSync('sleep 0.2');
    const s2 = readStat();

    const deltaIdle = s2.idle - s1.idle;
    const deltaTotal = s2.total - s1.total;
    const usage = deltaTotal > 0 ? (1 - deltaIdle / deltaTotal) * 100 : 0;
    return usage.toFixed(1);
  } catch (e) {
    // Fallback: use top
    try {
      const out = execSync("top -bn1 | grep 'Cpu(s)'", { encoding: 'utf8' });
